// limiterImpl implements the Limiter interface using a token bucket per key.
type limiterImpl struct {
	mu     sync.Mutex
	clock  Clock
	rate   int           // tokens added per window
	window time.Duration // window duration
	burst  int           // maximum bucket size (if 0, defaults to rate)

	// per-key bucket state
	buckets map[string]*bucket
