// bucket holds the token count and the last refill timestamp.
type bucket struct {
	tokens float64
	last   time.Time
}

// newLimiter creates a new Limiter implementation.
func newLimiter(cfg Config, clock Clock) Limiter {
	if cfg.Rate <= 0 {
		panic("Rate must be positive")
	}
	if cfg.Window <= 0 {
		panic("Window must be positive")
	}
	if cfg.Burst < 0 {
		panic("Burst cannot be negative")
	}
	// If Burst is zero, treat it as equal to Rate.
	burst := cfg.Burst
	if burst == 0 {
		burst = cfg.Rate
	}
	if clock == nil {
		clock = realClock{}
	}
	return &limiterImpl{
		clock:   clock,
		rate:    cfg.Rate,
		window:  cfg.Window,
		burst:   burst,
		buckets: make(map[string]*bucket),
	}
}

// Allow checks if a request for the given key is permitted.
func (l *limiterImpl) Allow(key string) bool {
	now := l.clock.Now()

	l.mu.Lock()
	b, ok := l.buckets[key]
	if !ok {
		// Initialize bucket with full burst capacity.
		b = &bucket{
			tokens: float64(l.burst),
			last:   now,
		}
		l.buckets[key] = b
	}
	// Refill tokens based on elapsed time.
	elapsed := now.Sub(b.last)
	if elapsed > 0 {
		added := float64(l.rate) * float64(elapsed) / float64(l.window)
		b.tokens += added
		if b.tokens > float64(l.burst) {
			b.tokens = float64(l.burst)
		}
		b.last = now
	}
	// Consume a token if available.
	if b.tokens >= 1.0 {
		b.tokens -= 1.0
		l.mu.Unlock()
		return true
	}
	l.mu.Unlock()
	return false
}

// Reset clears the rate‑limiting state for the specified key.
func (l *limiterImpl) Reset(key string) {
	l.mu.Lock()
	delete(l.buckets, key)
	l.mu.Unlock()
}

// realClock provides the actual system time when a Clock is not supplied.
type realClock struct{}

func (realClock) Now() time.Time { return time.Now() }
EOF
